import { Tabs as TabsPrimitive } from "@base-ui/react/tabs";
import { createStyleContext } from "@/registry/bare/lib/create-style-context";
import { createPropSplitter } from "@/registry/bare/lib/split-variant-props";
import { tabsStyles } from "./styles";
import type { VariantProps } from "@/registry/bare/lib/tv.config";

type TabsStyles = ReturnType<typeof tabsStyles>;
type TabsVariantProps = VariantProps<typeof tabsStyles>;

const { StyleContext, useStyles } =
  createStyleContext<TabsStyles>("Tabs");
const splitProps = createPropSplitter(tabsStyles);

export { useStyles as useTabsStyles };

interface TabsRootProps extends TabsPrimitive.Root.Props, TabsVariantProps {
  className?: string;
  styles?: TabsStyles;
}

export function TabsRoot(props: TabsRootProps) {
  const [variantProps, { className, styles, ...htmlProps }] = splitProps(
    props as Record<string, any>,
  );
  const s = styles ?? tabsStyles(variantProps);
  return (
    <StyleContext value={s}>
      <TabsPrimitive.Root
        {...htmlProps}
        className={s.root({ class: className })}
        data-slot="tabs"
      />
    </StyleContext>
  );
}

import { Tabs as TabsPrimitive } from "@base-ui/react/tabs";
import { useTabsStyles } from "./tabs-root";

interface TabsListProps extends TabsPrimitive.List.Props {
  className?: string;
}

export function TabsList({ className, ...props }: TabsListProps) {
  const styles = useTabsStyles();
  return (
    <TabsPrimitive.List
      {...props}
      className={styles.list({ class: className })}
      data-slot="tabs-list"
    />
  );
}

interface TabsTabProps extends TabsPrimitive.Tab.Props {
  className?: string;
}

export function TabsTab({ className, ...props }: TabsTabProps) {
  const styles = useTabsStyles();
  return (
    <TabsPrimitive.Tab
      {...props}
      className={styles.tab({ class: className })}
      data-slot="tabs-tab"
    />
  );
}

interface TabsIndicatorProps extends TabsPrimitive.Indicator.Props {
  className?: string;
}

export function TabsIndicator({
  className,
  ...props
}: TabsIndicatorProps) {
  const styles = useTabsStyles();
  return (
    <TabsPrimitive.Indicator
      {...props}
      className={styles.indicator({ class: className })}
      data-slot="tabs-indicator"
    />
  );
}

interface TabsPanelProps extends TabsPrimitive.Panel.Props {
  className?: string;
}

export function TabsPanel({ className, ...props }: TabsPanelProps) {
  const styles = useTabsStyles();
  return (
    <TabsPrimitive.Panel
      {...props}
      className={styles.panel({ class: className })}
      data-slot="tabs-panel"
    />
  );
}

import { tv } from "@/registry/bare/lib/tv.config";

export const tabsStyles = tv({
  slots: {
    root: [""],
    list: [""],
    tab: [""],
    indicator: [""],
    panel: [""],
  },
});

export { TabsRoot as Tabs } from "./tabs-root";
export { TabsList, TabsTab, TabsIndicator, TabsPanel } from "./tabs-parts";
export { tabsStyles } from "./styles";
